using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using Microsoft.Agents.AI.ChatCompletion;
using Microsoft.Extensions.AI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

const string modelId = "gpt-4o-mini-2024-07-18";

// --- Build the chat client through MEAI ---
IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

// --- Tools ---
var searchTool = new WebSearchTool();
var notesTool = new NotesTool();

var tools = new AIFunction[]
{
    AIFunctionFactory.Create(searchTool.SearchWeb),
    AIFunctionFactory.Create(notesTool.SaveNote),
    AIFunctionFactory.Create(notesTool.GetNotes),
};

// --- Agent ---
var agent = new ChatClientAgent(chatClient,
    """
    You are a research assistant. When the user provides a topic:
    1. Search the web for relevant information (multiple searches if needed).
    2. Save key findings as notes using the note-taking tool.
    3. After gathering enough information, retrieve all notes and produce
       a well-structured summary with key facts and sources.
    Be thorough but concise. Always cite sources.
    """)
{
    Name = "ResearchAgent",
};

// --- Run ---
Console.WriteLine("=== Research Agent ===");
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrWhiteSpace(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\nResearching \"{topic}\"...\n");

var history = new List<ChatMessage>
{
    new(ChatRole.User, $"Research the following topic and summarize your findings: {topic}"),
};

var options = new AgentInvokeOptions
{
    MaximumIterations = 15,
    ChatOptions = new ChatOptions
    {
        Temperature = 0f,
        Tools = [.. tools],
    },
};

await foreach (var message in agent.InvokeStreamingAsync(history, options))
{
    if (message.Role == ChatRole.Assistant)
    {
        Console.Write(message.Text);
    }
}

Console.WriteLine("\n\n=== Research Complete ===");
if (notesTool.NoteCount > 0)
{
    Console.WriteLine($"({notesTool.NoteCount} notes captured during research)");
}

// --- Tool Implementations ---

/// <summary>Searches the web using DuckDuckGo Instant Answer API (no key required).</summary>
sealed class WebSearchTool
{
    private static readonly HttpClient Http = new()
    {
        DefaultRequestHeaders = { { "User-Agent", "ResearchAgent/1.0" } },
    };

    [Description("Search the web for information on a query. Returns a summary and related topics.")]
    public async Task<string> SearchWeb(
        [Description("The search query")] string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://api.duckduckgo.com/?q={encoded}&format=json&no_html=1&skip_disambig=1";

            using var response = await Http.GetAsync(url);
            response.EnsureSuccessStatusCode();

            using var doc = await JsonDocument.ParseAsync(await response.Content.ReadAsStreamAsync());
            var root = doc.RootElement;

            var results = new List<string>();

            var abstractText = root.GetProperty("AbstractText").GetString();
            var abstractSource = root.GetProperty("AbstractSource").GetString();
            var abstractUrl = root.GetProperty("AbstractURL").GetString();
            if (!string.IsNullOrWhiteSpace(abstractText))
            {
                results.Add($"[{abstractSource}] ({abstractUrl}): {abstractText}");
            }

            if (root.TryGetProperty("RelatedTopics", out var topics))
            {
                foreach (var topic in topics.EnumerateArray().Take(5))
                {
                    var text = topic.TryGetProperty("Text", out var t) ? t.GetString() : null;
                    var firstUrl = topic.TryGetProperty("FirstURL", out var u) ? u.GetString() : null;
                    if (!string.IsNullOrWhiteSpace(text))
                    {
                        results.Add($"- {text} ({firstUrl})");
                    }
                }
            }

            return results.Count > 0
                ? string.Join("\n", results)
                : $"No results found for '{query}'. Try a different search term.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}. Try a different query.";
        }
    }
}

/// <summary>Simple in-memory note-taking tool for the agent.</summary>
sealed class NotesTool
{
    private readonly List<string> _notes = [];

    public int NoteCount => _notes.Count;

    [Description("Save a research note. Use this to record key findings from web searches.")]
    public string SaveNote(
        [Description("The note content to save")] string note)
    {
        _notes.Add(note);
        return $"Note #{_notes.Count} saved.";
    }

    [Description("Retrieve all saved research notes.")]
    public string GetNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes saved yet.";
        }

        return string.Join("\n", _notes.Select((n, i) => $"[{i + 1}] {n}"));
    }
}

